var e=[{id:`L4_1`,type:`dialog`,speaker:`HILDE_FENRIR_ADMIN_NULL`,text:{KOREA:`아직 멀었나, 나유빈?!`,JPN:`まだかかるのか？　イチノセ・カオル！`,ENG:`How much longer, Yubin?!`,TWN:`還沒好嗎，羅瑜斌？！`},stage:{bg:`PROLOGUE_03`,slots:{L:{char_id:`HILDE_FENRIR_ADMIN_NULL`,face:`UNIT_IDLE`},C:null,R:null}}},{id:`L5_1`,type:`dialog`,speaker:`HILDE_FENRIR_ADMIN_NULL`,text:{KOREA:`침식 쐐기는 모두 처리했다.`,JPN:`侵食くさびはすべて排除した。`,ENG:`All the Corrupted Wedges have been neutralized.`,TWN:`侵蝕釘已經全部解決掉了。`},stage:{bg:`PROLOGUE_03`,slots:{L:{char_id:`HILDE_FENRIR_ADMIN_NULL`,face:`UNIT_IDLE`},C:null,R:null}}},{id:`L6_1`,type:`dialog`,speaker:`HILDE_FENRIR_ADMIN_NULL`,text:{KOREA:`지금 당장 떠나야 해!`,JPN:`今すぐここを発たねばならん！`,ENG:`We have to leave now!`,TWN:`我們現在就要馬上離開！`},stage:{bg:`PROLOGUE_03`,slots:{L:{char_id:`HILDE_FENRIR_ADMIN_NULL`,face:`UNIT_IDLE`},C:null,R:null}}},{id:`L7_1`,type:`dialog`,speaker:`LEESUYEON_ADMIN_NULL_NULL`,text:{KOREA:`그래! 이 느림보야! 뭘 꾸물거리는 거야?`,JPN:`そうだよ！　このノロマ！　何ぐずぐずしてるの？`,ENG:`That's right! Come on, you slowpoke! What's taking you so long?`,TWN:`就是啊！慢死了！拖拖拉拉的搞什麼鬼？`},stage:{bg:`PROLOGUE_03`,slots:{L:{char_id:`HILDE_FENRIR_ADMIN_NULL`,face:`UNIT_IDLE`},C:null,R:{char_id:`LEESUYEON_ADMIN_NULL_NULL`,face:`UNIT_SERIOUS`}}}},{id:`L9_1`,type:`dialog`,speaker:`NAYUBIN_ADMIN_NULL_NULL`,text:{KOREA:`거의 끝났어요!`,JPN:`だいたい終わりました！`,ENG:`Almost there!`,TWN:`就要完成了！`},stage:{bg:`PROLOGUE_03`,slots:{L:null,C:{char_id:`NAYUBIN_ADMIN_NULL_NULL`,face:`UNIT_SERIOUS`},R:null}}},{id:`L10_1`,type:`dialog`,speaker:`NAYUBIN_ADMIN_NULL_NULL`,text:{KOREA:`긴급 차원 도약 절차 개시!`,JPN:`緊急次元跳躍プロセス開始！`,ENG:`Starting emergency dimension jump sequence!`,TWN:`啟動緊急次元躍遷！`},stage:{bg:`PROLOGUE_03`,slots:{L:null,C:{char_id:`NAYUBIN_ADMIN_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L11_1`,type:`dialog`,speaker:`NAYUBIN_ADMIN_NULL_NULL`,text:{KOREA:`이터니움 드라이브 기동 준비 완료!`,JPN:`エタニウムドライブ起動準備完了！`,ENG:`Eternium Drive ready to go!`,TWN:`永恆之金引擎啟動準備完成！`},stage:{bg:`PROLOGUE_03`,slots:{L:null,C:{char_id:`NAYUBIN_ADMIN_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L12_1`,type:`dialog`,speaker:`NAYUBIN_ADMIN_NULL_NULL`,text:{KOREA:`......지금 바로 상위차원으로 부상합니다!`,JPN:`……ただちに上位次元へ浮上します！`,ENG:`...We're entering the upper dimension now!`,TWN:`……現在開始向高次元躍出！`},stage:{bg:`PROLOGUE_03`,slots:{L:null,C:{char_id:`NAYUBIN_ADMIN_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L13_1`,type:`dialog`,speaker:`NAYUBIN_ADMIN_NULL_NULL`,text:{KOREA:`이터니움 드라이브 기동!`,JPN:`エタニウムドライブ起動！`,ENG:`Eternium Drive activated!`,TWN:`永恆之金引擎啟動！`},stage:{bg:`PROLOGUE_03`,slots:{L:null,C:{char_id:`NAYUBIN_ADMIN_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L15_1`,type:`dialog`,speaker:`HILDE_FENRIR_ADMIN_NULL`,text:{KOREA:`전원! 충격 대비!`,JPN:`総員！　衝撃に備えろ！`,ENG:`All hands! Brace for impact!`,TWN:`全員！做好衝擊準備！`},stage:{bg:`PROLOGUE_03`,slots:{L:null,C:{char_id:`HILDE_FENRIR_ADMIN_NULL`,face:`UNIT_SERIOUS`},R:null}}},{id:`L19_1`,type:`dialog`,speaker:null,text:{KOREA:`대장님! 적들이 계속 몰려듭니다!`,JPN:`隊長！　敵が続々と襲ってきます！`,ENG:`Sir! The enemies keep closing in!`,TWN:`長官！敵人不斷地向這裡聚集！`},stage:{bg:`COUNTERSIDE_RED`,slots:{L:null,C:null,R:null}}},{id:`L20_1`,type:`dialog`,speaker:null,text:{KOREA:`더는 막을 수 없습니다!`,JPN:`これ以上は防げません！`,ENG:`We can't hold them back much longer!`,TWN:`我們快要擋不住了！`},stage:{bg:`COUNTERSIDE_RED`,slots:{L:null,C:null,R:null}}},{id:`L21_1`,type:`dialog`,speaker:`SHILED_ADMIN_NULL_COMMANDER`,text:{KOREA:`버텨! 이 자식들아!`,JPN:`耐えてみせろ！　このバカども！`,ENG:`Hold your ground! You morons!`,TWN:`撐住啊！你們這群混蛋！`},stage:{bg:`COUNTERSIDE_RED`,slots:{L:null,C:{char_id:`SHILED_ADMIN_NULL_COMMANDER`,face:`UNIT_IDLE`},R:null}}},{id:`L22_1`,type:`dialog`,speaker:`SHILED_ADMIN_NULL_COMMANDER`,text:{KOREA:`헛소리 할 시간에 총알이나 한 발 더 쏘라고!`,JPN:`無駄口を叩いてる暇があったら、弾を一発でも多く撃ち込め！`,ENG:`Stop running your mouth and keep shooting!`,TWN:`有時間抱怨還不如多開一槍！`},stage:{bg:`COUNTERSIDE_RED`,slots:{L:null,C:{char_id:`SHILED_ADMIN_NULL_COMMANDER`,face:`UNIT_IDLE`},R:null}}},{id:`L26_1`,type:`dialog`,speaker:`HIVE_VOICE_NULL_NULL`,text:{KOREA:`<color=#ffd34c>7시 방향 2km 지역, 제 4종 침식파 발생.</color>`,JPN:`<color=#ffd34c>7時方向2km地点、第4種侵食波発生。</color>`,ENG:`<color=#ffd34c>Category 4 Corruption ray detected 2km to your 7 o'clock.</color>`,TWN:`<color=#ffd34c>7點鐘方向2km區域，出現4級侵蝕波。</color>`},stage:{bg:`MAINSTREAM_002000`,slots:{L:null,C:null,R:null}}},{id:`L27_1`,type:`dialog`,speaker:`HIVE_VOICE_NULL_NULL`,text:{KOREA:`<color=#ffd34c>대형 변이종 접근.</color>`,JPN:`<color=#ffd34c>大型変異種接近。</color>`,ENG:`<color=#ffd34c>Large mutated species approaching.</color>`,TWN:`<color=#ffd34c>大型變異體正在接近。</color>`},stage:{bg:`MAINSTREAM_002000`,slots:{L:null,C:null,R:null}}}];export{e as default};